#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE 256

#define MAX_PD (3.0e6f)

#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f

#define FACTOR_CHIP 0.5f

#define amb_temp 80.0f
#define t_chip 0.0005f
#define chip_height 0.016f
#define chip_width 0.016f

__kernel void hotspot(
    int num_iterations,
    __global float* power,
    __global float* temp_in,
    __global float* temp_out,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    const float Rx_1 = 1.f / Rx;
    const float Ry_1 = 1.f / Ry;
    const float Rz_1 = 1.f / Rz;
    const float Cap_1 = step / Cap;

    int global_col = get_global_id(0);
    int global_row = get_global_id(1);

    if (global_col >= col || global_row >= row)
        return;

    // Calculate block boundaries
    int blockCol = get_group_id(0);
    int blockRow = get_group_id(1);
    int chunks_in_row = col / BLOCK_SIZE_C;
    int chunks_in_col = row / BLOCK_SIZE_R;

    int r_start = blockRow * BLOCK_SIZE_R;
    int c_start = blockCol * BLOCK_SIZE_C;
    int r_end = r_start + BLOCK_SIZE_R > row ? row : r_start + BLOCK_SIZE_R;
    int c_end = c_start + BLOCK_SIZE_C > col ? col : c_start + BLOCK_SIZE_C;

    float delta = 0.f;

    // Check if on border block
    int on_border_block = (r_start == 0) || (c_start == 0) || (r_end == row) || (c_end == col);

    int r = global_row;
    int c = global_col;

    if (on_border_block)
    {
        // Handle edges and corners explicitly
        if ((r == 0) && (c == 0))
        {
            delta = (Cap_1) * (power[0] +
                (temp_in[1] - temp_in[0]) * Rx_1 +
                (temp_in[col] - temp_in[0]) * Ry_1 +
                (amb_temp - temp_in[0]) * Rz_1);
        }
        else if ((r == 0) && (c == col - 1))
        {
            delta = (Cap_1) * (power[c] +
                (temp_in[c - 1] - temp_in[c]) * Rx_1 +
                (temp_in[c + col] - temp_in[c]) * Ry_1 +
                (amb_temp - temp_in[c]) * Rz_1);
        }
        else if ((r == row - 1) && (c == col - 1))
        {
            delta = (Cap_1) * (power[r * col + c] +
                (temp_in[r * col + c - 1] - temp_in[r * col + c]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[r * col + c]) * Ry_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }
        else if ((r == row - 1) && (c == 0))
        {
            delta = (Cap_1) * (power[r * col] +
                (temp_in[r * col + 1] - temp_in[r * col]) * Rx_1 +
                (temp_in[(r - 1) * col] - temp_in[r * col]) * Ry_1 +
                (amb_temp - temp_in[r * col]) * Rz_1);
        }
        else if (r == 0)
        {
            delta = (Cap_1) * (power[c] +
                (temp_in[c + 1] + temp_in[c - 1] - 2.0f * temp_in[c]) * Rx_1 +
                (temp_in[col + c] - temp_in[c]) * Ry_1 +
                (amb_temp - temp_in[c]) * Rz_1);
        }
        else if (c == col - 1)
        {
            delta = (Cap_1) * (power[r * col + c] +
                (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * temp_in[r * col + c]) * Ry_1 +
                (temp_in[r * col + c - 1] - temp_in[r * col + c]) * Rx_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }
        else if (r == row - 1)
        {
            delta = (Cap_1) * (power[r * col + c] +
                (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * temp_in[r * col + c]) * Rx_1 +
                (temp_in[(r - 1) * col + c] - temp_in[r * col + c]) * Ry_1 +
                (amb_temp - temp_in[r * col + c]) * Rz_1);
        }
        else if (c == 0)
        {
            delta = (Cap_1) * (power[r * col] +
                (temp_in[(r + 1) * col] + temp_in[(r - 1) * col] - 2.0f * temp_in[r * col]) * Ry_1 +
                (temp_in[r * col + 1] - temp_in[r * col]) * Rx_1 +
                (amb_temp - temp_in[r * col]) * Rz_1);
        }
        temp_out[r * col + c] = temp_in[r * col + c] + delta;
    }
    else
    {
        // Interior points: apply stencil formula
        delta = Cap_1 * (power[r * col + c] +
            (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.f * temp_in[r * col + c]) * Ry_1 +
            (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.f * temp_in[r * col + c]) * Rx_1 +
            (amb_temp - temp_in[r * col + c]) * Rz_1);

        temp_out[r * col + c] = temp_in[r * col + c] + delta;
    }

    // Multiple iterations: loop here
    for (int iter = 1; iter < num_iterations; iter++)
    {
        barrier(CLK_GLOBAL_MEM_FENCE);
        // Swap buffers pointers: handled outside kernel in host code
        // This kernel handles one iteration at a time.
        // So no further action here.
    }
}
